# SLO: 95% of agent sessions complete in under 8 seconds
histogram_quantile(0.95,
  sum by (le, agent_name) (
    rate(agent_session_duration_seconds_bucket[5m])
  )
)

# SLO: 99% of LLM TTFT under 2 seconds
histogram_quantile(0.99,
  sum by (le, model) (
    rate(llm_ttft_seconds_bucket[5m])
  )
)

# Identify which tool is the latency bottleneck
topk(5,
  histogram_quantile(0.95,
    sum by (le, tool_name) (
      rate(agent_tool_call_duration_seconds_bucket[10m])
    )
  )
)
